205: NS_IMETHODIMP
206: nsObserverService::AddObserver(nsIObserver* aObserver, const char* aTopic,
207:                                bool aOwnsWeak) {
208:   LOG(("nsObserverService::AddObserver(%p: %s, %s)", (void*)aObserver, aTopic,
209:        aOwnsWeak ? "weak" : "strong"));
210: 
211:   MOZ_TRY(EnsureValidCall());
212:   if (NS_WARN_IF(!aObserver) || NS_WARN_IF(!aTopic)) {
213:     return NS_ERROR_INVALID_ARG;
214:   }
215: 
216:   MOZ_TRY(FilterHttpOnTopics(aTopic));
217: 
218:   nsObserverList* observerList = mObserverTopicTable.PutEntry(aTopic);
219:   if (!observerList) {
220:     return NS_ERROR_OUT_OF_MEMORY;
221:   }
222: 
223:   return observerList->AddObserver(aObserver, aOwnsWeak);
224: }
225: 
226: NS_IMETHODIMP
227: nsObserverService::RemoveObserver(nsIObserver* aObserver, const char* aTopic) {
228:   LOG(("nsObserverService::RemoveObserver(%p: %s)", (void*)aObserver, aTopic));
229: 
230:   if (mShuttingDown) {
231:     // The service is shutting down. Let's ignore this call.
232:     return NS_OK;
233:   }
234: 
235:   MOZ_TRY(EnsureValidCall());
236:   if (NS_WARN_IF(!aObserver) || NS_WARN_IF(!aTopic)) {
237:     return NS_ERROR_INVALID_ARG;
238:   }
239: 
240:   nsObserverList* observerList = mObserverTopicTable.GetEntry(aTopic);
241:   if (!observerList) {
242:     return NS_ERROR_FAILURE;
243:   }
244: 
245:   return observerList->RemoveObserver(aObserver);
246: }
247: 
248: NS_IMETHODIMP
249: nsObserverService::EnumerateObservers(const char* aTopic,
250:                                       nsISimpleEnumerator** anEnumerator) {
251:   LOG(("nsObserverService::EnumerateObservers(%s)", aTopic));
252: 
253:   MOZ_TRY(EnsureValidCall());
254:   if (NS_WARN_IF(!anEnumerator) || NS_WARN_IF(!aTopic)) {
255:     return NS_ERROR_INVALID_ARG;
256:   }
257: 
258:   nsObserverList* observerList = mObserverTopicTable.GetEntry(aTopic);
259:   if (!observerList) {
260:     return NS_NewEmptyEnumerator(anEnumerator);
261:   }
262: 
263:   observerList->GetObserverList(anEnumerator);
264:   return NS_OK;
265: }
266: 
267: // Enumerate observers of aTopic and call Observe on each.
268: NS_IMETHODIMP nsObserverService::NotifyObservers(nsISupports* aSubject,
269:                                                  const char* aTopic,
270:                                                  const char16_t* aSomeData) {
271:   LOG(("nsObserverService::NotifyObservers(%s)", aTopic));
272: 
273:   MOZ_TRY(EnsureValidCall());
274:   if (NS_WARN_IF(!aTopic)) {
275:     return NS_ERROR_INVALID_ARG;
276:   }
277: 
278:   MOZ_ASSERT(AppShutdown::IsNoOrLegalShutdownTopic(aTopic));
279: 
280:   AUTO_PROFILER_MARKER_TEXT("NotifyObservers", OTHER, MarkerStack::Capture(),
281:                             nsDependentCString(aTopic));
282:   AUTO_PROFILER_LABEL_DYNAMIC_CSTR_NONSENSITIVE(
283:       "nsObserverService::NotifyObservers", OTHER, aTopic);
284: 
285:   nsObserverList* observerList = mObserverTopicTable.GetEntry(aTopic);
286:   if (observerList) {
287:     observerList->NotifyObservers(aSubject, aTopic, aSomeData);
288:   }
289: 
290:   return NS_OK;
291: }
292: 
293: NS_IMETHODIMP
294: nsObserverService::UnmarkGrayStrongObservers() {
295:   MOZ_TRY(EnsureValidCall());
296: 
297:   nsCOMArray<nsIObserver> strongObservers;
298:   for (auto iter = mObserverTopicTable.Iter(); !iter.Done(); iter.Next()) {
299:     nsObserverList* aObserverList = iter.Get();
300:     if (aObserverList) {
301:       aObserverList->AppendStrongObservers(strongObservers);
302:     }
303:   }
304: 
305:   for (uint32_t i = 0; i < strongObservers.Length(); ++i) {
306:     xpc_TryUnmarkWrappedGrayObject(strongObservers[i]);
307:   }
308: 
309:   return NS_OK;
310: }
311: 
312: bool nsObserverService::HasObservers(const char* aTopic) {
313:   return mObserverTopicTable.Contains(aTopic);
314: }
