{"meta": null, "content": [{"type": "text", "text": "{"content":"1: /* -*- Mode: C++; tab-width: 8; indent-tabs-mode: nil; c-basic-offset: 2 -*-\n2:  * This Source Code Form is subject to the terms of the Mozilla Public\n3:  * License, v. 2.0. If a copy of the MPL was not distributed with this\n4:  * file, You can obtain one at http://mozilla.org/MPL/2.0/. */\n5: \n6: #include \"nsBrowserStatusFilter.h\"\n7: #include \"nsITimer.h\"\n8: #include \"nsString.h\"\n9: #include \"nsThreadUtils.h\"\n10: \n11: using namespace mozilla;\n12: \n13: //-----------------------------------------------------------------------------\n14: // nsBrowserStatusFilter \u003cpublic\u003e\n15: //-----------------------------------------------------------------------------\n16: \n17: nsBrowserStatusFilter::nsBrowserStatusFilter(bool aDisableStateChangeFilters)\n18:     : mTarget(GetMainThreadSerialEventTarget()),\n19:       mCurProgress(0),\n20:       mMaxProgress(0),\n21:       mCurrentPercentage(0),\n22:       mStatusIsDirty(true),\n23:       mIsLoadingDocument(false),\n24:       mDelayedStatus(false),\n25:       mDelayedProgress(false),\n26:       mDisableStateChangeFilters(aDisableStateChangeFilters) {}\n27: \n28: nsBrowserStatusFilter::~nsBrowserStatusFilter() {\n29:   if (mTimer) {\n30:     mTimer-\u003eCancel();\n31:   }\n32: }\n33: \n34: //-----------------------------------------------------------------------------\n35: // nsBrowserStatusFilter::nsISupports\n36: //-----------------------------------------------------------------------------\n37: \n38: NS_IMPL_CYCLE_COLLECTION_WEAK(nsBrowserStatusFilter, mListener, mTarget)\n39: \n40: NS_INTERFACE_MAP_BEGIN_CYCLE_COLLECTION(nsBrowserStatusFilter)\n41:   NS_INTERFACE_MAP_ENTRY(nsIWebProgress)\n42:   NS_INTERFACE_MAP_ENTRY(nsIWebProgressListener)\n43:   NS_INTERFACE_MAP_ENTRY(nsIWebProgressListener2)\n44:   NS_INTERFACE_MAP_ENTRY(nsISupportsWeakReference)\n45:   NS_INTERFACE_MAP_ENTRY_AMBIGUOUS(nsISupports, nsIWebProgress)\n46: NS_INTERFACE_MAP_END\n47: \n48: NS_IMPL_CYCLE_COLLECTING_ADDREF(nsBrowserStatusFilter)\n49: NS_IMPL_CYCLE_COLLECTING_RELEASE(nsBrowserStatusFilter)\n50: \n51: //-----------------------------------------------------------------------------\n52: // nsBrowserStatusFilter::nsIWebProgress\n53: //-----------------------------------------------------------------------------\n54: \n55: NS_IMETHODIMP\n56: nsBrowserStatusFilter::AddProgressListener(nsIWebProgressListener* aListener,\n57:                                            uint32_t aNotifyMask) {\n58:   mListener = aListener;\n59:   return NS_OK;\n60: }\n61: \n62: NS_IMETHODIMP\n63: nsBrowserStatusFilter::RemoveProgressListener(\n64:     nsIWebProgressListener* aListener) {\n65:   if (aListener == mListener) mListener = nullptr;\n66:   return NS_OK;\n67: }\n68: \n69: NS_IMETHODIMP\n70: nsBrowserStatusFilter::GetBrowsingContextXPCOM(\n71:     mozilla::dom::BrowsingContext** aResult) {\n72:   MOZ_ASSERT_UNREACHABLE(\"nsBrowserStatusFilter::GetBrowsingContextXPCOM\");\n73:   return NS_ERROR_NOT_IMPLEMENTED;\n74: }\n75: \n76: mozilla::dom::BrowsingContext* nsBrowserStatusFilter::GetBrowsingContext() {\n77:   MOZ_ASSERT_UNREACHABLE(\"nsBrowserStatusFilter::GetBrowsingContext\");\n78:   return nullptr;\n79: }\n80: \n81: NS_IMETHODIMP\n82: nsBrowserStatusFilter::GetDOMWindow(mozIDOMWindowProxy** aResult) {\n83:   MOZ_ASSERT_UNREACHABLE(\"nsBrowserStatusFilter::GetDOMWindow\");\n84:   return NS_ERROR_NOT_IMPLEMENTED;\n85: }\n86: \n87: NS_IMETHODIMP\n88: nsBrowserStatusFilter::GetIsTopLevel(bool* aIsTopLevel) {\n89:   *aIsTopLevel = false;\n90:   MOZ_ASSERT_UNREACHABLE(\"nsBrowserStatusFilter::GetIsTopLevel\");\n91:   return NS_ERROR_NOT_IMPLEMENTED;\n92: }\n93: \n94: NS_IMETHODIMP\n95: nsBrowserStatusFilter::GetIsLoadingDocument(bool* aIsLoadingDocument) {\n96:   MOZ_ASSERT_UNREACHABLE(\"nsBrowserStatusFilter::GetIsLoadingDocument\");\n97:   return NS_ERROR_NOT_IMPLEMENTED;\n98: }\n99: \n100: NS_IMETHODIMP\n101: nsBrowserStatusFilter