124: NS_IMETHODIMP
125: nsBrowserStatusFilter::OnStateChange(nsIWebProgress* aWebProgress,
126:                                      nsIRequest* aRequest, uint32_t aStateFlags,
127:                                      nsresult aStatus) {
128:   if (!mListener) return NS_OK;
129: 
130:   if (aStateFlags & STATE_START) {
131:     // Reset members on beginning of document loading, but we don't want
132:     // subframe document loading followed by the root document loading
133:     // resets members accidentally, so for non-toplevel load we check if
134:     // there hasn't been a document load started.
135:     if (aStateFlags & STATE_IS_DOCUMENT) {
136:       bool isTopLevel = false;
137:       aWebProgress->GetIsTopLevel(&isTopLevel);
138:       if (!mIsLoadingDocument || isTopLevel) {
139:         ResetMembers();
140:       }
141:       mIsLoadingDocument = true;
142:     }
143:   } else if (aStateFlags & STATE_STOP) {
144:     // Flush pending status / progress update during document loading.
145:     if (mIsLoadingDocument) {
146:       bool isLoadingDocument = true;
147:       aWebProgress->GetIsLoadingDocument(&isLoadingDocument);
148:       mIsLoadingDocument &= isLoadingDocument;
149: 
150:       if (mTimer) {
151:         mTimer->Cancel();
152:         CallDelayedProgressListeners();
153: 
154:         // CallDelayedProgressListeners() may trigger OnStatusChange and/or
155:         // OnProgressChange handlers, which can run JS and may even call
156:         // RemoveProgressListener.
157:         if (!mListener) {
158:           return NS_OK;
159:         }
160:       }
161:     }
162:   } else {
163:     // No need to forward this state change.
164:     return NS_OK;
165:   }
166: 
167:   // Only notify listener for STATE_IS_NETWORK or STATE_IS_REDIRECTED_DOCUMENT
168:   // unless mDisableStateChangeFilters is set.
169:   if (mDisableStateChangeFilters || aStateFlags & STATE_IS_NETWORK ||
170:       aStateFlags & STATE_IS_REDIRECTED_DOCUMENT) {
171:     return mListener->OnStateChange(aWebProgress, aRequest, aStateFlags,
172:                                     aStatus);
173:   }
174: 
175:   return NS_OK;
176: }
