178: NS_IMETHODIMP
179: nsBrowserStatusFilter::OnProgressChange(nsIWebProgress* aWebProgress,
180:                                         nsIRequest* aRequest,
181:                                         int32_t aCurSelfProgress,
182:                                         int32_t aMaxSelfProgress,
183:                                         int32_t aCurTotalProgress,
184:                                         int32_t aMaxTotalProgress) {
185:   if (!mListener) return NS_OK;
186: 
187:   //
188:   // limit frequency of calls to OnProgressChange
189:   //
190: 
191:   mCurProgress = (int64_t)aCurTotalProgress;
192:   mMaxProgress = (int64_t)aMaxTotalProgress;
193: 
194:   if (mDelayedProgress) return NS_OK;
195: 
196:   if (!mDelayedStatus) {
197:     MaybeSendProgress();
198:     StartDelayTimer();
199:   }
200: 
201:   mDelayedProgress = true;
202: 
203:   return NS_OK;
204: }
