292: void nsBrowserStatusFilter::ResetMembers() {
293:   mMaxProgress = 0;
294:   mCurProgress = 0;
295:   mCurrentPercentage = 0;
296:   mStatusIsDirty = true;
297:   // We don't reset mIsLoadingDocument here.
298:   // It's controlled by OnStateChange based on webProgress states.
299: }
