301: void nsBrowserStatusFilter::MaybeSendProgress() {
302:   if (mCurProgress > mMaxProgress || mCurProgress <= 0) return;
303: 
304:   // check our percentage
305:   int32_t percentage = (int32_t)double(mCurProgress) * 100 / mMaxProgress;
306: 
307:   // The progress meter only updates for increases greater than 3 percent
308:   if (percentage > (mCurrentPercentage + 3)) {
309:     mCurrentPercentage = percentage;
310:     // XXX truncates 64-bit to 32-bit
311:     mListener->OnProgressChange(nullptr, nullptr, 0, 0, (int32_t)mCurProgress,
312:                                 (int32_t)mMaxProgress);
313:   }
314: }
315: 
316: void nsBrowserStatusFilter::MaybeSendStatus() {
317:   if (mStatusIsDirty) {
318:     mListener->OnStatusChange(nullptr, nullptr, NS_OK, mStatusMsg.get());
319:     mCurrentStatusMsg = mStatusMsg;
320:     mStatusIsDirty = false;
321:   }
322: }
