333: void nsBrowserStatusFilter::CallDelayedProgressListeners() {
334:   mTimer = nullptr;
335: 
336:   if (!mListener) return;
337: 
338:   if (mDelayedStatus) {
339:     mDelayedStatus = false;
340:     MaybeSendStatus();
341:   }
342: 
343:   if (mDelayedProgress) {
344:     mDelayedProgress = false;
345:     MaybeSendProgress();
346:   }
347: }
