#include "nsThreadUtils.h"

////////////////////////////////////////////////////////////////////////////////
// nsMyObserverService Implementation

// NS_IMPL_ISUPPORTS expands to provide QueryInterface, AddRef, and Release
// following the XPCOM reference counting pattern.
NS_IMPL_ISUPPORTS(nsMyObserverService, nsIObserverService)

nsMyObserverService::nsMyObserverService() : mShuttingDown(false) {}

nsMyObserverService::~nsMyObserverService() { Shutdown(); }

void nsMyObserverService::Shutdown() {
  if (mShuttingDown) {
    return;
  }
  mShuttingDown = true;
  mObserverTopicTable.Clear();
}

NS_IMETHODIMP
nsMyObserverService::AddObserver(nsIObserver* aObserver, const char* aTopic,
                                 bool aOwnsWeak) {
  if (mShuttingDown) {
    return NS_ERROR_ILLEGAL_DURING_SHUTDOWN;
  }
  if (NS_WARN_IF(!aObserver) || NS_WARN_IF(!aTopic)) {
    return NS_ERROR_INVALID_ARG;
  }

  nsObserverList* observerList = mObserverTopicTable.PutEntry(aTopic);
  if (!observerList) {
    return NS_ERROR_OUT_OF_MEMORY;
  }

  return observerList->AddObserver(aObserver, aOwnsWeak);
}

NS_IMETHODIMP
nsMyObserverService::RemoveObserver(nsIObserver* aObserver,
                                    const char* aTopic) {
  if (mShuttingDown) {
    return NS_OK;
  }
  if (NS_WARN_IF(!aObserver) || NS_WARN_IF(!aTopic)) {
    return NS_ERROR_INVALID_ARG;
  }

  nsObserverList* observerList = mObserverTopicTable.GetEntry(aTopic);
  if (!observerList) {
    return NS_ERROR_FAILURE;
  }

  return observerList->RemoveObserver(aObserver);
}

NS_IMETHODIMP
nsMyObserverService::NotifyObservers(nsISupports* aSubject, const char* aTopic,
                                     const char16_t* aSomeData) {
  if (mShuttingDown) {
    return NS_ERROR_ILLEGAL_DURING_SHUTDOWN;
  }
  if (NS_WARN_IF(!aTopic)) {
    return NS_ERROR_INVALID_ARG;
  }

  nsObserverList* observerList = mObserverTopicTable.GetEntry(aTopic);
  if (observerList) {
    observerList->NotifyObservers(aSubject, aTopic, aSomeData);
  }

  return NS_OK;
}

NS_IMETHODIMP
nsMyObserverService::EnumerateObservers(const char* aTopic,
                                        nsISimpleEnumerator** anEnumerator) {
  if (NS_WARN_IF(!anEnumerator) || NS_WARN_IF(!aTopic)) {
    return NS_ERROR_INVALID_ARG;
  }

  nsObserverList* observerList = mObserverTopicTable.GetEntry(aTopic);
  if (!observerList) {
    return NS_NewEmptyEnumerator(anEnumerator);
  }

  observerList->GetObserverList(anEnumerator);
  return NS_OK;
}

bool nsMyObserverService::HasObservers(const char* aTopic) {
  return mObserverTopicTable.Contains(aTopic);
}

